args.sparql:
SELECT ?founderLabel WHERE {
  ?stadium wdt:P17 wd:Q499 ;
          wdt:P119 ?capacity .
  ?stadium wdt:P131 ?city .
  ?team wdt:P170 ?stadium ;
        wdt:P576 wd:Q2623222 .
  wd:Q2623222 wdt:P580 ?start ;
              wdt:P582 ?end .
  FILTER (YEAR(?start) <= 2010 && YEAR(?end) >= 2011)
  ?city wdt:P6198 ?founder .
  OPTIONAL { ?founder rdfs:label ?founderLabel FILTER (LANG(?founderLabel) = "en") }
} ORDER BY DESC(?capacity) LIMIT 1

